class Solution {
    public long minEnd(int n, int x) {
        long ans = x;
        for (int i = 0; i < n - 1; i++) {
            ans = (ans << 1) | 1;
            if ((ans & x) != x) {
                ans = (ans & ~(1L << (63 - Integer.numberOfLeadingZeros(x)))) | (x & (1L << (63 - Integer.numberOfLeadingZeros(x))));
            }
        }
        return ans;
    }
}
